// Узел: Code after Jarvis
// Цель: Распарсить ответ от JARVIS и объединить его с важными данными,
// полученными напрямую из узла "If New Actionable Guest Message".

// Получаем JSON-ответ от JARVIS (AI агент)
const jarvisNodeOutputObject = $json; // $json здесь - это вывод узла JARVIS HOSTIFY

let parsedJarvisContent;

// 1. Проверяем и извлекаем строку с JSON от Jarvis
if (!jarvisNodeOutputObject || typeof jarvisNodeOutputObject.output !== 'string') {
  console.error("Error: Jarvis node output is not in the expected format { output: string }.", JSON.stringify(jarvisNodeOutputObject));
  return {
    json: {
      should_reply: false,
      jarvis_reply_message: "Error: Unexpected output format from Jarvis agent node.",
      jarvis_processing_error_in_code_node: "Jarvis agent node did not return { output: string }.",
      jarvis_thread_id: null,
      retrieved_firestore_doc_id: null, // Добавляем поля по умолчанию
      retrieved_is_actionable: null
    }
  };
}

let rawJsonStringFromJarvis = jarvisNodeOutputObject.output;

// 2. Очищаем строку от Markdown-обертки (если есть)
// УЛУЧШЕННАЯ ВЕРСИЯ очистки
console.log("Raw JSON string from Jarvis (before cleaning):", JSON.stringify(rawJsonStringFromJarvis));
// Сначала удаляем начало блока, если он есть
if (rawJsonStringFromJarvis.startsWith('```json')) {
  rawJsonStringFromJarvis = rawJsonStringFromJarvis.substring('```json'.length);
} else if (rawJsonStringFromJarvis.startsWith('```')) {
  rawJsonStringFromJarvis = rawJsonStringFromJarvis.substring('```'.length);
}
// Затем удаляем конец блока, если он есть
if (rawJsonStringFromJarvis.endsWith('```')) {
  rawJsonStringFromJarvis = rawJsonStringFromJarvis.substring(0, rawJsonStringFromJarvis.length - '```'.length);
}
rawJsonStringFromJarvis = rawJsonStringFromJarvis.trim(); // Убираем пробелы по краям
console.log("Cleaned JSON string from Jarvis (after cleaning):", JSON.stringify(rawJsonStringFromJarvis));


// 3. Парсим очищенную строку в объект JSON
try {
  parsedJarvisContent = JSON.parse(rawJsonStringFromJarvis);
} catch (e) {
  console.error("Failed to parse cleaned JSON string from Jarvis:", rawJsonStringFromJarvis, "Error:", e);
  return {
    json: {
      should_reply: false,
      jarvis_reply_message: "Error: Could not parse JSON content from Jarvis response.",
      jarvis_processing_error_in_code_node: e.message,
      raw_jarvis_content_for_debug: rawJsonStringFromJarvis,
      jarvis_thread_id: null,
      retrieved_firestore_doc_id: null,
      retrieved_is_actionable: null
    }
  };
}

// 4. Проверяем наличие всех ОБЯЗАТЕЛЬНЫХ полей в распарсенном ответе Jarvis
const requiredJarvisFields = ['should_reply', 'reply_message', 'thread_id', 'guest_name', 'guest_message'];
const missingFields = requiredJarvisFields.filter(field => typeof parsedJarvisContent[field] === 'undefined');

if (missingFields.length > 0) {
  const errorMessage = `Error: Parsed Jarvis response is missing one or more key fields: ${missingFields.join(', ')}. Parsed_response: ${JSON.stringify(parsedJarvisContent)}`;
  console.error(errorMessage);
  return {
    json: {
      should_reply: false,
      jarvis_reply_message: "Error: Key fields missing in parsed Jarvis response.",
      jarvis_processing_error_in_code_node: `Missing fields: ${missingFields.join(', ')}`,
      jarvis_thread_id: parsedJarvisContent.thread_id || null,
      retrieved_firestore_doc_id: null,
      retrieved_is_actionable: null
    }
  };
}

// 5. Извлекаем "сквозные" данные напрямую из узла "If New Actionable Guest Message"
// ЗАМЕНИТЕ "2605ba55-8af6-4a1f-98e1-1cf94e13cc66" НА АКТУАЛЬНЫЙ ID ВАШЕГО УЗЛА "If New Actionable Guest Message"
// Этот ID можно найти в URL, когда вы выбираете узел, или в JSON экспорте workflow.
// Судя по вашему workflow JSON (`Hostify_JarvisGEMINI_Telegram_2_12.json`), ID узла "If New Actionable Guest Message" - это `2605ba55-8af6-4a1f-98e1-1cf94e13cc66`.

let retrievedData = {
  retrieved_firestore_doc_id: null,
  retrieved_is_actionable: null
  // Можно добавить поля по умолчанию для других ожидаемых "сквозных" данных
  // retrieved_original_guest_message_from_prepare: null,
  // retrieved_guest_name_from_prepare: null,
};

// Получаем данные из указанного узла. Это массив items, берем первый (и единственный в данном случае).
// ВАЖНО: Узел, на который ссылаемся, должен был выполниться в этом прогоне workflow.
let ifNodeItems;
try {
  ifNodeItems = $('If New Actionable Guest Message').all();
} catch (e) {
  console.warn('Warning: Unable to access output of referenced node. Node may not have executed.', e.message);
}

if (ifNodeItems && ifNodeItems.length > 0 && ifNodeItems[0].json && ifNodeItems[0].json.json) {
  const ifNodeData = ifNodeItems[0].json.json; // Данные из узла "If New Actionable Guest Message"
  retrievedData.retrieved_firestore_doc_id = ifNodeData.processed_firestore_doc_id;
  retrievedData.retrieved_is_actionable = ifNodeData.processed_isActionable;
  // Раскомментируйте и добавьте другие поля, если они нужны и есть в ifNodeData:
  // retrievedData.retrieved_original_guest_message_from_prepare = ifNodeData.data_from_prepare_guest_message;
  // retrievedData.retrieved_guest_name_from_prepare = ifNodeData.data_from_prepare_guest_name;
  // retrievedData.retrieved_guest_id_from_prepare = ifNodeData.data_from_prepare_guest_id;
} else {
  console.warn(`Warning: Could not retrieve data from node "If New Actionable Guest Message" (ID: 2605ba55-8af6-4a1f-98e1-1cf94e13cc66) or data structure is unexpected. 'Retrieved' data will be null.`);
}

// 6. Формируем итоговый JSON-объект для вывода из этого узла
return {
  json: {
    // Данные от JARVIS (переименованы с префиксом jarvis_ для избежания конфликтов имен)
    should_reply: parsedJarvisContent.should_reply,
    jarvis_reply_message: parsedJarvisContent.reply_message,
    jarvis_thread_id: parsedJarvisContent.thread_id,
    jarvis_guest_name: parsedJarvisContent.guest_name,
    jarvis_guest_id: parsedJarvisContent.guest_id,
    jarvis_original_guest_message: parsedJarvisContent.guest_message,
    jarvis_guest_thumb: parsedJarvisContent.guest_thumb || "",

    // "Сквозные" данные из узла "If New Actionable Guest Message"
    ...retrievedData // Используем spread operator для добавления всех полей из retrievedData
  }
};

// Функция для рекурсивного удаления null/undefined значений. Не изменилась.
function removeNulls(obj) {
  if (obj === null || obj === undefined) {
    return undefined;
  }
  if (Array.isArray(obj)) {
    return obj.map(removeNulls).filter(item => item !== undefined);
  }
  if (typeof obj === 'object') {
    const cleaned = {};
    for (const [key, value] of Object.entries(obj)) {
      const cleanedValue = removeNulls(value);
      if (cleanedValue !== undefined) {
        cleaned[key] = cleanedValue;
      }
    }
    return Object.keys(cleaned).length > 0 ? cleaned : undefined;
  }
  return obj;
}

// --- НАЧАЛО ЛОГИКИ УЗЛА ---

const items = $input.all();

let messagesData = null;
let reservationData = null;
let listingData = null;

// [+] Соседние секции, которые в реальном payload идут рядом с listing
let amenitiesData = null;
let roomsData = null;
let photosData = null;
let descriptionData = null;
let detailsData = null;

for (const item of items) {
  if (item.json?.messages) {
    messagesData = item.json;
  } else if (item.json?.reservation) {
    reservationData = item.json.reservation;
  } else if (item.json?.listing) {
    listingData = item.json.listing;
  }

  // [+] Подхватываем «плоские» соседние поля, если они присутствуют в этом item
  if (Array.isArray(item.json?.amenities)) amenitiesData = item.json.amenities;
  if (Array.isArray(item.json?.rooms)) roomsData = item.json.rooms;
  if (Array.isArray(item.json?.photos)) photosData = item.json.photos;
  if (item.json?.description) descriptionData = item.json.description;
  if (item.json?.details) detailsData = item.json.details;
}

// --- Создаем обогащенный listing_context ---
let listingContext = {};
if (listingData) {
  const customFields = listingData.custom_fields || {};

  // Источники массивов: сначала берём «плоские», fallback — из listing
  const amenities = amenitiesData || listingData.amenities || [];
  const rooms = roomsData || listingData.rooms || [];
  const photos = photosData || listingData.photos || [];

  listingContext = {
    name: listingData.name || listingData.nickname || "Property",

    address: {
      // Логика custom_fields сохранена
      building_and_apartment: customFields.custom_field_600000968,
      city: listingData.city,
      country: listingData.country,
      neighbourhood: listingData.neighbourhood
    },

    location: {
      lat: listingData.lat,
      lng: listingData.lng,
      neighbourhood: listingData.neighbourhood
    },

    check_in: {
      start: listingData.checkin_start || "15:00",
      end: listingData.checkin_end || "23:00"
    },
    check_out: listingData.checkout || "12:00",

    rules: {
      min_nights: listingData.min_nights,
      max_nights: listingData.max_nights,
      // [+] Реальная вместимость, если есть; иначе прежняя логика
      max_guests: (listingData.person_capacity ?? detailsData?.person_capacity ?? listingData.guests_included),
      pets_allowed: listingData.pets_allowed > 0,
      smoking_allowed: listingData.smoking_allowed > 0,
      events_allowed: listingData.events_allowed > 0
    },

    // Возвращаем ранее утерянные данные, если они не пустые
    ...(amenities.length > 0 && { amenities }),
    ...(rooms.length > 0 && { rooms }),
    ...(photos.length > 0 && {
      photos: photos.map(p => ({
        description: p.description,
        thumbnail_file: p.thumbnail_file,
        original_file: p.original_file,
        sort_order: p.sort_order
      }))
    }),

    // Добавляем контакты, очищая от null
    contacts: removeNulls({
      main: listingData.main_contact,
      emergency: listingData.emergency_contact,
      checkin: listingData.checkin_contact,
      cleaning: listingData.cleaning_contact
    }),

    // СВЯТАЯ СВЯТЫХ: access из custom_fields
    access: {
      door_code: customFields.custom_field_600000915,
      parking_spot: customFields.custom_field_600000883,
      wifi_info: customFields.custom_field_600000884,
      building_info: customFields.custom_field_600000968
    },

    // Информационное поле для подтверждения логики
    priority_info: {
      use_only_custom_fields: true
    },

    // Структурируем детали, объединяя listing и details (без добавления новых ключей)
    property_details: removeNulls({
      bedrooms: listingData.bedrooms ?? detailsData?.bedrooms,
      bathrooms: listingData.bathrooms ?? detailsData?.bathrooms,
      area: listingData.area ?? detailsData?.area,
      floor: listingData.floor ?? detailsData?.floor,
      beds: listingData.beds ?? detailsData?.beds
    })
  };

  // Возвращаем description, беря «плоский» блок с fallback на listing.description
  const desc = descriptionData || listingData.description;
  if (desc && Object.keys(desc).some(k => desc[k] && desc[k].toString().trim().length > 0)) {
    listingContext.description = removeNulls(desc);
  }
}

// --- Создаем reservation_summary. Логика не изменилась. ---
let reservationSummary = {};
if (reservationData) {
  const now = new Date();
  const checkInDate = new Date(reservationData.checkIn);
  const checkOutDate = new Date(reservationData.checkOut);

  let timeStatus;
  if (reservationData.status === 'cancelled') {
    timeStatus = "cancelled";
  } else if (checkOutDate < now) {
    timeStatus = "past_completed";
  } else if (checkInDate <= now && checkOutDate >= now) {
    timeStatus = "current_stay";
  } else if (checkInDate > now) {
    timeStatus = "future_booking";
  } else {
    timeStatus = "unknown";
  }

  reservationSummary = removeNulls({
    internal_id: reservationData.id,
    external_id: reservationData.channel_reservation_id || reservationData.confirmation_code,
    source_channel: reservationData.source,
    status: reservationData.status,
    check_in_date: reservationData.checkIn,
    check_out_date: reservationData.checkOut,
    nights: reservationData.nights,
    guest_count: reservationData.guests,
    listing_id: reservationData.listing_id,
    booking_guest_id: reservationData.guest_id,
    total_amount: reservationData.subtotal,
    amount_paid: reservationData.paid_sum,
    amount_due: reservationData.due,
    payment_status: reservationData.paid_part,
    currency: reservationData.currency,
    guest_language: reservationData.language_code,
    notes: reservationData.notes,
    cancelled_at: reservationData.cancelled_at,
    time_status: timeStatus
  });
}

// Объединяем всё в один объект
const combinedData = removeNulls({
  thread_id: messagesData?.thread?.id,
  messages: messagesData?.messages?.map(m =>
    removeNulls({
      id: m.id,
      message: m.message,
      created: m.created,
      guest_name: m.guest_name,
      guest_id: m.guest_id,
      is_sms: m.is_sms,
      is_automatic: m.is_automatic,
      pinned: m.pinned
    })
  ) || [],
  reservation_summary: reservationSummary,
  listing_context: removeNulls(listingContext)
});

return [{
  json: combinedData
}];

// Code узел: Parse Webhook Body
// Добавь между новым Webhook и If1

let parsedBody;

// Проверяем, есть ли body и это строка
if ($json.body && typeof $json.body === 'string') {
  try {
    parsedBody = JSON.parse($json.body);
    console.log("Parsed SNS message type:", parsedBody.Type);
  } catch (e) {
    console.error("Failed to parse body:", e);
    return [{
      json: {
        error: "Failed to parse webhook body",
        originalBody: $json.body
      }
    }];
  }
} else if ($json.body && typeof $json.body === 'object') {
  // Если body уже объект
  parsedBody = $json.body;
} else {
  // Если данные прямо в $json
  parsedBody = $json;
}

// Возвращаем распарсенные данные
return [{
  json: parsedBody
}];

// Code узел: Transform Webhook to Existing Format
// Преобразует данные от webhook в формат, который ожидает существующая логика

// Данные от webhook
const webhookData = $json;

// Преобразуем в формат, который ожидает "HOSTIFY Request Messages"
// Эмулируем структуру как будто это элемент из Loop Over Items
return [{
  json: {
    id: webhookData.thread_id,
    thread_id: webhookData.thread_id,
    booking_id: webhookData.reservation_id,
    guest_id: webhookData.guest_id || webhookData.sent_by,
    message: webhookData.message,
    created: webhookData.created,
    // Добавляем поля, которые может ожидать старая логика
    thread: {
      id: webhookData.thread_id,
      reservation_id: webhookData.reservation_id
    },
    // Флаг для отладки
    _source: "webhook",
    _original_webhook_data: webhookData
  }
}];

// --- ID сообщения, которое вызвало ЭТОТ запуск ---
const originalMessageId = $('Code').first().json.message_id;

// --- Массив сообщений Hostify ---
const messages = $json.messages || [];
const latestMessage = messages[0];
const latestId = latestMessage?.id ?? null;

// --- Если нет сообщений — считаем запуск старым и гасим ---
if (!latestMessage || typeof latestMessage.id !== 'number') {
  return []; // Остановка workflow
}

// --- Если message_id не совпадает с последним — гасим ---
if (originalMessageId !== latestId) {
  return []; // Остановка workflow
}

// --- Это самый свежий запуск — пропускаем дальше Hostify-ответ ---
return [{
  json: {
    ...$json
  }
}];

