const crypto = require("crypto");

function getHeader(headers, name) {
  const target = name.toLowerCase();
  for (const [k, v] of Object.entries(headers || {})) {
    if (k.toLowerCase() === target) return Array.isArray(v) ? v[0] : v;
  }
  return "";
}

function getVar(name, fallback = "") {
  try {
    if ($vars && typeof $vars.get === "function") {
      const v = $vars.get(name);
      if (v !== undefined && v !== null && v !== "") return v;
    }
  } catch (_) {}
  try {
    if ($vars && $vars[name] !== undefined && $vars[name] !== null && $vars[name] !== "") {
      return $vars[name];
    }
  } catch (_) {}
  return fallback;
}

const input = $json || {};
const headers = input.headers || {};
const bodyObj = input.body || {};
const rawBody =
  typeof input.rawBody === "string"
    ? input.rawBody
    : typeof bodyObj === "string"
    ? bodyObj
    : JSON.stringify(bodyObj);

const secret = getVar("N8N_WEBHOOK_SECRET", "");
const callbackUrl = getVar("APP_CALLBACK_URL", "");
const hostifyValidateUrl = getVar("HOSTIFY_VALIDATE_URL", "https://api-rms.hostify.com/inbox");

if (!secret) {
  return [{ json: { ok: false, error: "Missing N8N_WEBHOOK_SECRET variable." } }];
}

const timestamp = getHeader(headers, "x-cohost-timestamp");
const signature = getHeader(headers, "x-cohost-signature");
const incomingIdempotencyKey =
  getHeader(headers, "x-cohost-idempotency-key") || crypto.randomUUID();

const expected = crypto
  .createHmac("sha256", secret)
  .update(`${timestamp}.${rawBody}`)
  .digest("hex");

let signatureValid = false;
if (timestamp && signature) {
  const sigBuf = Buffer.from(signature);
  const expBuf = Buffer.from(expected);
  if (sigBuf.length === expBuf.length) {
    signatureValid = crypto.timingSafeEqual(sigBuf, expBuf);
  }
}

if (!signatureValid) {
  return [{ json: { ok: false, error: "Invalid signature." } }];
}

let payload;
try {
  payload = typeof bodyObj === "object" && bodyObj !== null ? bodyObj : JSON.parse(rawBody);
} catch (e) {
  return [{ json: { ok: false, error: "Invalid JSON payload." } }];
}

const tenantId = payload.tenantId;
const mode = payload.mode;
const telegramChatId = payload.telegramChatId || null;
const hostifyApiKey = payload.hostifyApiKey || null;
const event = payload.event;

if (!tenantId || !event) {
  return [{ json: { ok: false, error: "tenantId and event are required." } }];
}

let hostifyOk = false;
let hostifyStatus = null;
let hostifyError = null;

if (!hostifyApiKey) {
  hostifyError = "hostifyApiKey is missing.";
} else {
  try {
    const hostifyResponse = await this.helpers.httpRequest({
      method: "GET",
      url: hostifyValidateUrl,
      headers: {
        "x-api-key": hostifyApiKey,
        Accept: "application/json",
      },
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    });

    hostifyStatus = hostifyResponse.statusCode;
    hostifyOk = hostifyStatus >= 200 && hostifyStatus < 300;

    if (!hostifyOk) {
      hostifyError =
        typeof hostifyResponse.body === "string"
          ? hostifyResponse.body
          : JSON.stringify(hostifyResponse.body ?? {});
    }
  } catch (e) {
    hostifyError = e.message;
  }
} // <-- important missing brace

const eventType = hostifyOk ? "n8n_sync_ok" : "n8n_sync_error";

const callbackPayload = {
  tenantId,
  eventType,
  payload: {
    mode,
    telegramChatId,
    validated: hostifyOk,
    hostifyStatus,
    error: hostifyError,
  },
};

let callbackSent = false;
let callbackStatus = null;
let callbackError = null;

if (callbackUrl) {
  const callbackBody = JSON.stringify(callbackPayload);
  const callbackTimestamp = Date.now().toString();
  const callbackSignature = crypto
    .createHmac("sha256", secret)
    .update(`${callbackTimestamp}.${callbackBody}`)
    .digest("hex");

  try {
    const callbackResponse = await this.helpers.httpRequest({
      method: "POST",
      url: callbackUrl,
      headers: {
        "content-type": "application/json",
        "x-cohost-timestamp": callbackTimestamp,
        "x-cohost-signature": callbackSignature,
        "x-cohost-idempotency-key": `${incomingIdempotencyKey}:callback`,
      },
      body: callbackPayload,
      json: true,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    });

    callbackStatus = callbackResponse.statusCode;
    callbackSent = callbackStatus >= 200 && callbackStatus < 300;

    if (!callbackSent) {
      callbackError =
        typeof callbackResponse.body === "string"
          ? callbackResponse.body
          : JSON.stringify(callbackResponse.body ?? {});
    }
  } catch (e) {
    callbackError = e.message;
  }
} else {
  callbackError = "APP_CALLBACK_URL is not configured.";
}

return [
  {
    json: {
      ok: hostifyOk,
      tenantId,
      eventType,
      hostifyStatus,
      hostifyError,
      callbackSent,
      callbackStatus,
      callbackError,
    },
  },
];

// A2: Build rich operational context for Telegram error alerts
// Input source: Error Trigger payload

const src = $json ?? {};

function firstDefined(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== '') return value;
  }
  return null;
}

function extractRunItems(errorPayload) {
  const runData = errorPayload?.execution?.data?.resultData?.runData;
  if (!runData || typeof runData !== 'object') return [];

  const items = [];
  for (const nodeRuns of Object.values(runData)) {
    if (!Array.isArray(nodeRuns)) continue;
    for (const run of nodeRuns) {
      const main = run?.data?.main;
      if (!Array.isArray(main)) continue;
      for (const branch of main) {
        if (!Array.isArray(branch)) continue;
        for (const item of branch) {
          if (item?.json && typeof item.json === 'object') items.push(item.json);
        }
      }
    }
  }

  return items;
}

function findContextValue(items, keys) {
  for (const item of items) {
    for (const key of keys) {
      if (item[key] !== undefined && item[key] !== null && item[key] !== '') return item[key];
    }
  }
  return null;
}

const runItems = extractRunItems(src);

const workflowName = firstDefined(src?.workflow?.name, src?.workflowName, 'unknown_workflow');
const workflowId = firstDefined(src?.workflow?.id, src?.workflowId, 'n/a');
const executionId = firstDefined(src?.execution?.id, src?.executionId, src?.id, 'n/a');
const executionUrl = firstDefined(src?.execution?.url, src?.executionUrl, 'n/a');
const failedNodeName = firstDefined(src?.lastNodeExecuted, src?.node?.name, src?.error?.node?.name, 'unknown_node');
const errorMessage = firstDefined(src?.error?.message, src?.message, src?.error?.description, 'Unknown error');

const tenantId = firstDefined(
  findContextValue(runItems, ['tenant_id', 'tenantId']),
  src?.tenant_id,
  src?.tenantId,
  'n/a'
);

const threadId = firstDefined(
  findContextValue(runItems, ['thread_id', 'threadId']),
  src?.thread_id,
  src?.threadId,
  'n/a'
);

const reservationId = firstDefined(
  findContextValue(runItems, ['reservation_id', 'reservationId', 'booking_id']),
  src?.reservation_id,
  src?.reservationId,
  src?.booking_id,
  'n/a'
);

const nowUtc = new Date().toISOString();

const alertText = [
  '🚨 WORKFLOW FAILURE',
  'Workflow: ' + workflowName,
  'Workflow ID: ' + workflowId,
  'Execution ID: ' + executionId,
  'Execution URL: ' + executionUrl,
  'Failed node: ' + failedNodeName,
  'Tenant: ' + tenantId,
  'Thread: ' + threadId,
  'Reservation: ' + reservationId,
  'Time (UTC): ' + nowUtc,
  '---',
  'Error: ' + errorMessage,
].join('\n');

return [{
  json: {
    ...src,
    workflow_name: workflowName,
    workflow_id: workflowId,
    execution_id: executionId,
    execution_url: executionUrl,
    failed_node_name: failedNodeName,
    tenant_id: tenantId,
    thread_id: threadId,
    reservation_id: reservationId,
    error_message: errorMessage,
    alert_text: alertText,
    alert_generated_at_utc: nowUtc,
  },
}];
